pub enum InstallResult {
    Installed { backup_path: PathBuf },
    AlreadyInstalled,
    Updated { backup_path: PathBuf },
    NotSupported(String),
    DryRun { would_install: bool },
    VersionTooOld { min_required: String, current: String },
